queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?lost_property a :LostProperties .
    ?lost_property p:Owner ?owner .
    BIND(?owner AS ?o0)
  }
  UNION
  {
    ?customer_complaints a :Complaints .
    ?customer_complaints p:CustomerName ?customername .
    ?customer_complaints p:Date ?date_f .
    FILTER(STR(?date_f) = "January 5, 2024")
    BIND(?customername AS ?o0)
  }
}

